<?php
$pageTitle='Performance Management';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('performance_management');
$pdo=getDB();$employees=$pdo->query('SELECT * FROM '.table('employees').' WHERE status="active" ORDER BY first_name,last_name')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'review');
    if($action==='review'){
      $number=nextScopedDocumentNumber($pdo,'performance_review',setting('performance_review_prefix','REV'),operationalScope($pdo));
      $pdo->prepare('INSERT INTO '.table('employee_performance_reviews').' (review_number,employee_id,review_period,start_date,end_date,rating,goals_score,manager_comments,employee_comments,status) VALUES (?,?,?,?,?,?,?,?,?,"draft")')->execute([$number,(int)$_POST['employee_id'],trim((string)$_POST['review_period']),trim((string)$_POST['start_date']),trim((string)$_POST['end_date']),max(0,(float)$_POST['rating']),max(0,(float)$_POST['goals_score']),trim((string)$_POST['manager_comments']),trim((string)$_POST['employee_comments'])]);flash('success','Performance review created.');
    }elseif($action==='goal'){
      $pdo->prepare('INSERT INTO '.table('employee_goals').' (employee_id,goal_title,target_metric,target_value,actual_value,due_date,status,notes) VALUES (?,?,?,?,?,?, "open", ?)')->execute([(int)$_POST['employee_id'],trim((string)$_POST['goal_title']),trim((string)$_POST['target_metric']),max(0,(float)$_POST['target_value']),max(0,(float)$_POST['actual_value']),trim((string)$_POST['due_date']),trim((string)$_POST['notes'])]);flash('success','Goal created.');
    }elseif($action==='complete_review'){
      $pdo->prepare('UPDATE '.table('employee_performance_reviews').' SET status="completed" WHERE id=?')->execute([(int)$_POST['id']]);flash('success','Review completed.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'performance-management']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/performance-management.php');
}
$reviews=$pdo->query('SELECT r.*,e.employee_code,e.first_name,e.last_name FROM '.table('employee_performance_reviews').' r LEFT JOIN '.table('employees').' e ON e.id=r.employee_id ORDER BY r.created_at DESC LIMIT 250')->fetchAll();
$goals=$pdo->query('SELECT g.*,e.employee_code,e.first_name,e.last_name FROM '.table('employee_goals').' g LEFT JOIN '.table('employees').' e ON e.id=g.employee_id ORDER BY g.created_at DESC LIMIT 100')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Employee Growth</div><h2 class="h4 mb-1">Performance Management</h2><p class="text-secondary mb-0">Manage performance reviews, employee goals, ratings, and management feedback.</p></div><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/employees.php"><?php echo t('Employees', 'الموظفون'); ?></a></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="review"><h2 class="h5 mb-3">Create Review</h2><label class="form-label">Employee</label><select class="form-select mb-2" name="employee_id"><?php foreach($employees as $e): ?><option value="<?php echo (int)$e['id']; ?>"><?php echo esc(employeeLabel($e)); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="review_period" value="<?php echo esc(date('Y')); ?> Review"><div class="row g-2"><div class="col-6"><input class="form-control" type="date" name="start_date" value="<?php echo esc(date('Y-01-01')); ?>"></div><div class="col-6"><input class="form-control" type="date" name="end_date" value="<?php echo esc(date('Y-12-31')); ?>"></div></div><div class="row g-2 mt-1"><div class="col-6"><label class="form-label">Rating</label><input class="form-control" type="number" step="0.1" min="0" max="5" name="rating" value="0"></div><div class="col-6"><label class="form-label">Goals Score</label><input class="form-control" type="number" step="0.1" min="0" max="5" name="goals_score" value="0"></div></div><label class="form-label mt-2">Manager Comments</label><textarea class="form-control mb-2" name="manager_comments" rows="2"></textarea><label class="form-label">Employee Comments</label><textarea class="form-control mb-3" name="employee_comments" rows="2"></textarea><button class="btn btn-brand w-100">Create Review</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="goal"><h2 class="h5 mb-3">Create Goal</h2><select class="form-select mb-2" name="employee_id"><?php foreach($employees as $e): ?><option value="<?php echo (int)$e['id']; ?>"><?php echo esc(employeeLabel($e)); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="goal_title" placeholder="Goal title"><input class="form-control mb-2" name="target_metric" placeholder="Metric"><div class="row g-2"><div class="col-6"><input class="form-control" type="number" step="0.01" name="target_value" placeholder="Target"></div><div class="col-6"><input class="form-control" type="number" step="0.01" name="actual_value" placeholder="Actual"></div></div><label class="form-label mt-2">Due Date</label><input class="form-control mb-2" type="date" name="due_date"><textarea class="form-control mb-3" name="notes" rows="2" placeholder="Notes"></textarea><button class="btn btn-outline-primary w-100">Create Goal</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Performance Reviews</h2><table class="table align-middle"><thead><tr><th>Review</th><th>Employee</th><th>Rating</th><th>Goals</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($reviews as $r): ?><tr><td><strong><?php echo esc($r['review_number']); ?></strong><div class="small text-secondary"><?php echo esc($r['review_period']); ?></div></td><td><?php echo esc(($r['employee_code']?:'').' '.$r['first_name'].' '.$r['last_name']); ?></td><td><?php echo number_format((float)$r['rating'],1); ?></td><td><?php echo number_format((float)$r['goals_score'],1); ?></td><td><span class="badge bg-<?php echo esc(statusTone($r['status'])); ?>"><?php echo esc($r['status']); ?></span></td><td class="text-end"><?php if($r['status']==='draft'): ?><form method="post"><input type="hidden" name="action" value="complete_review"><input type="hidden" name="id" value="<?php echo (int)$r['id']; ?>"><button class="btn btn-sm btn-outline-success">Complete</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if(!$reviews): ?><tr><td colspan="6" class="text-secondary">No reviews yet.</td></tr><?php endif; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Goals</h2><table class="table"><thead><tr><th>Goal</th><th>Employee</th><th>Progress</th><th>Due</th><th>Status</th></tr></thead><tbody><?php foreach($goals as $g): $pct=(float)$g['target_value']>0?round((float)$g['actual_value']/(float)$g['target_value']*100):0; ?><tr><td><strong><?php echo esc($g['goal_title']); ?></strong><div class="small text-secondary"><?php echo esc($g['target_metric']); ?></div></td><td><?php echo esc($g['employee_code'].' '.$g['first_name'].' '.$g['last_name']); ?></td><td><?php echo number_format($pct,1); ?>%</td><td><?php echo esc($g['due_date']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($g['status'])); ?>"><?php echo esc($g['status']); ?></span></td></tr><?php endforeach; ?><?php if(!$goals): ?><tr><td colspan="5" class="text-secondary">No goals yet.</td></tr><?php endif; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>